	defer f.Close()

	fmt.Fprintf(f, "User JWT: %s\n", userJWT)
	fmt.Fprintf(f, "Notifications Count: %d\n", count)
	fmt.Fprintf(f, "Latest Notification Title: %s\n", latestTitle)
}

